var checkStrings = function(s1, s2) {
    function group(s, parity) {
        const arr = [];
        for (let i = parity; i < s.length; i += 2) arr.push(s[i]);
        return arr.sort().join('');
    }
    return group(s1, 0) === group(s2, 0) && group(s1, 1) === group(s2, 1);
};
